import{_ as a,o as l,c as i,ai as o}from"./chunks/framework.CaiDwmc7.js";const _=JSON.parse('{"title":"01 环境与账号准备（Web + API）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/stage-1-llm/01-setup.md","filePath":"ai/stage-1-llm/01-setup.md"}'),t={name:"ai/stage-1-llm/01-setup.md"};function r(n,e,d,c,s,h){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_01-环境与账号准备-web-api" tabindex="-1">01 环境与账号准备（Web + API） <a class="header-anchor" href="#_01-环境与账号准备-web-api" aria-label="Permalink to “01 环境与账号准备（Web + API）”">​</a></h1><blockquote><p>目标：在 30～60 分钟内完成“能用 Web 端 + 能用 API 调用”，为后续脚本/小工具做准备。</p></blockquote><h2 id="_1-你需要准备什么" tabindex="-1">1）你需要准备什么 <a class="header-anchor" href="#_1-你需要准备什么" aria-label="Permalink to “1）你需要准备什么”">​</a></h2><ul><li><strong>一个稳定可用的大模型 Web 端</strong>：用于日常学习与 Prompt 迭代。</li><li><strong>一个可用的 API Key</strong>：用于写脚本/做小工具。</li><li><strong>本机 Python 环境</strong>：推荐用 <code>uv</code>（更快、更省心）。</li></ul><h2 id="_2-python-uv-推荐" tabindex="-1">2）Python + uv（推荐） <a class="header-anchor" href="#_2-python-uv-推荐" aria-label="Permalink to “2）Python + uv（推荐）”">​</a></h2><h3 id="_2-1-安装与校验-思路" tabindex="-1">2.1 安装与校验（思路） <a class="header-anchor" href="#_2-1-安装与校验-思路" aria-label="Permalink to “2.1 安装与校验（思路）”">​</a></h3><ul><li>安装 <code>uv</code> 后，保证能在终端执行： <ul><li><code>uv --version</code></li><li><code>python --version</code></li></ul></li></ul><h3 id="_2-2-建一个最小项目目录" tabindex="-1">2.2 建一个最小项目目录 <a class="header-anchor" href="#_2-2-建一个最小项目目录" aria-label="Permalink to “2.2 建一个最小项目目录”">​</a></h3><p>在任意目录创建项目（示例）：</p><ul><li><code>uv init</code></li><li><code>uv venv</code></li></ul><blockquote><p>你后面所有小脚本都建议放到一个独立目录里，别污染你的 VitePress 项目。</p></blockquote><h2 id="_3-api-key-与环境变量-必须" tabindex="-1">3）API Key 与环境变量（必须） <a class="header-anchor" href="#_3-api-key-与环境变量-必须" aria-label="Permalink to “3）API Key 与环境变量（必须）”">​</a></h2><p>推荐用环境变量存 Key（不要写进代码、不要提交 Git）：</p><ul><li>Windows（示例思路）：在系统环境变量里新增 <code>OPENAI_API_KEY</code>（或你使用的平台对应变量名）。</li><li>也可以用 <code>.env</code> 文件（结合 <code>python-dotenv</code>），但注意 <code>.env</code> 要加入 <code>.gitignore</code>。</li></ul><h2 id="_4-最小可验证动作-今天就做完" tabindex="-1">4）最小可验证动作（今天就做完） <a class="header-anchor" href="#_4-最小可验证动作-今天就做完" aria-label="Permalink to “4）最小可验证动作（今天就做完）”">​</a></h2><ul><li>用 Web 端做 3 个任务： <ul><li>让模型把一段技术文章总结成 5 点</li><li>让模型把一段“面试回答”改写得更口语</li><li>让模型按固定 Markdown 模板输出</li></ul></li><li>为阶段一后续文章预留一个目录： <ul><li><code>outputs/</code>：存放生成的 Markdown</li></ul></li></ul>',16)])])}const p=a(t,[["render",r]]);export{_ as __pageData,p as default};
